#!/bin/bash
set -e
cd /workspaces/time-to-energize

# Create all required directories
mkdir -p app/src/components app/src/pages/api app/src/lib app/src/styles app/data app/public data .devcontainer

# Fix bad filename with space
mv 'app/data/lancium_sites (2).json' app/data/lancium_sites.json 2>/dev/null || true
rm -f 'download' 'download (3)' 2>/dev/null || true
mv sites.ts app/src/pages/api/sites.ts 2>/dev/null || true

# Write app/next.config.js
echo '' | base64 -d > app/next.config.js
# Write app/postcss.config.js
echo 'bW9kdWxlLmV4cG9ydHMgPSB7CiAgcGx1Z2luczogewogICAgdGFpbHdpbmRjc3M6IHt9LAogICAgYXV0b3ByZWZpeGVyOiB7fSwKICB9LAp9Cg==' | base64 -d > app/postcss.config.js
# Write app/tailwind.config.ts
echo '' | base64 -d > app/tailwind.config.ts
# Write app/src/styles/globals.css
echo '' | base64 -d > app/src/styles/globals.css
# Write app/src/components/StatsBar.tsx
echo '' | base64 -d > app/src/components/StatsBar.tsx
# Write app/src/pages/index.tsx
echo '' | base64 -d > app/src/pages/index.tsx
# Write app/src/pages/_document.tsx
echo '' | base64 -d > app/src/pages/_document.tsx
# Write app/src/pages/api/sites.ts
echo '' | base64 -d > app/src/pages/api/sites.ts
# Write app/src/pages/api/tenants.ts
echo '' | base64 -d > app/src/pages/api/tenants.ts
# Write app/.env.example
echo 'IyBDb3B5IHRoaXMgZmlsZSB0byAuZW52LmxvY2FsIGFuZCBmaWxsIGluIHlvdXIgdmFsdWVzCiMgR2V0IGEgTWFwYm94IHRva2VuIGF0IGh0dHBzOi8vYWNjb3VudC5tYXBib3guY29tL2FjY2Vzcy10b2tlbnMvCk5FWFRfUFVCTElDX01BUEJPWF9UT0tFTj1way5ZT1VSX1RPS0VOX0hFUkUK' | base64 -d > app/.env.example
# Write app/data/lancium_sites.json
echo '' | base64 -d > app/data/lancium_sites.json
# Write app/data/lancium_tenants.json
echo '' | base64 -d > app/data/lancium_tenants.json
# Write data/lancium_sites.json
echo '' | base64 -d > data/lancium_sites.json
# Write data/lancium_tenants.json
echo '' | base64 -d > data/lancium_tenants.json
# Write data/lancium_sites.csv
echo '' | base64 -d > data/lancium_sites.csv
# Write data/lancium_tenants.csv
echo '' | base64 -d > data/lancium_tenants.csv
# Write .gitignore
echo '' | base64 -d > .gitignore

# Create .env.local if missing
[ -f app/.env.local ] || cp app/.env.example app/.env.local

echo '--- File structure ---'
find . -not -path '*/.git/*' -not -path '*/node_modules/*' -not -path '*/.next/*' -type f | sort

echo '--- Installing dependencies ---'
cd app && npm install
echo '--- READY: run npm run dev ---'
